): WallConnectivityJoin[] {
  const toleranceMm = options.toleranceMm ?? DEFAULT_TOLERANCE_MM;
  const joinsById = new Map<string, WallConnectivityJoin>();
  const byLevel = new Map<string, WallConnectivityWall[]>();
